```python
from schematics.types import MultilingualStringType as SchematicsMultilingualStringType, random_string, get_value_in


class MultilingualStringType(SchematicsMultilingualStringType):
    def _mock(self, context=None):
        return {
            'fr': random_string(get_value_in(self.min_length, self.max_length)),
